import type { SentryModuleOptions } from '@ntegral/nestjs-sentry';

/**
 * Sentry configuration (README §2.6 Error Tracking).
 * Captures unhandled 500s, Prisma errors, and BullMQ failures. Expected business
 * 4xx (404/409/422) are filtered out in the GlobalExceptionFilter, not here.
 * Disabled (no DSN) ⇒ the SDK becomes a no-op, so local dev needs no Sentry.
 */
export function buildSentryOptions(): SentryModuleOptions {
  const dsn = process.env.SENTRY_DSN;
  return {
    dsn: dsn ?? '',
    enabled: Boolean(dsn),
    environment: process.env.NODE_ENV ?? 'development',
    release: process.env.APP_VERSION ?? '0.0.0',
    // Modest sampling — traces are primarily handled by OpenTelemetry (§2.6).
    tracesSampleRate: process.env.NODE_ENV === 'production' ? 0.1 : 0,
    logLevels: ['error'],
  };
}
